193→// CaptureBookmark creates a new bookmark item.
194→func (s *Service) CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input BookmarkInput) (*Item, error) {
195→	if input.URL == "" {
196→		return nil, fmt.Errorf("item: capture bookmark: url is required")
197→	}
198→	if input.Source == "" {
199→		input.Source = "api"
200→	}
201→	if input.Sensitivity == "" {
202→		input.Sensitivity = "normal"
203→	}
204→
205→	tags := input.Tags
206→	if tags == nil {
207→		tags = []string{}
208→	}
209→
210→	metadata := buildBookmarkMetadata(input.Selection, input.Referrer)
211→	metadataJSON, err := json.Marshal(metadata)
212→	if err != nil {
213→		return nil, fmt.Errorf("item: capture bookmark: marshal metadata: %w", err)
214→	}
215→
216→	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_url, source_url, tags, source, metadata, auto_metadata)
217→		VALUES ($1, 'bookmark', 'pending', $2, $3, $4, $5, $6, $7, $8, '{}')
218→		RETURNING %s`, itemColumns)
219→
220→	row := s.pool.QueryRow(ctx, query,
221→		ownerID, input.Sensitivity, input.Title, input.URL, input.URL, tags, input.Source, metadataJSON)
222→
223→	it, err := scanItem(row)
224→	if err != nil {
225→		return nil, fmt.Errorf("item: capture bookmark: %w", err)
226→	}
227→	return it, nil
228→}
