230→// buildBookmarkMetadata constructs a metadata map from optional bookmark provenance fields.
231→func buildBookmarkMetadata(selection, referrer *string) map[string]any {
232→	m := make(map[string]any)
233→	if selection != nil && *selection != "" {
234→		m["selection"] = *selection
235→	}
236→	if referrer != nil && *referrer != "" {
237→		m["referrer"] = *referrer
238→	}
239→	return m
240→}
