310→// Update partially updates an item. Only non-nil fields in input are changed.
311→func (s *Service) Update(ctx context.Context, ownerID, itemID uuid.UUID, input UpdateInput) (*Item, error) {
312→	sets := []string{}
313→	args := []any{ownerID, itemID}
314→	paramIdx := 3
315→
316→	if input.Title != nil {
317→		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
318→		args = append(args, *input.Title)
319→		paramIdx++
320→	}
321→	if input.Tags != nil {
322→		sets = append(sets, fmt.Sprintf("tags = $%d", paramIdx))
323→		args = append(args, input.Tags)
324→		paramIdx++
325→	}
326→	if input.Sensitivity != nil {
327→		sets = append(sets, fmt.Sprintf("sensitivity = $%d", paramIdx))
328→		args = append(args, *input.Sensitivity)
329→		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
330→	}
331→
332→	if len(sets) == 0 {
333→		return s.GetByID(ctx, ownerID, itemID)
334→	}
335→
336→	query := fmt.Sprintf(`UPDATE items SET %s WHERE owner_id = $1 AND id = $2 RETURNING %s`,
337→		joinSets(sets), itemColumns)
338→
339→	row := s.pool.QueryRow(ctx, query, args...)
340→	it, err := scanItem(row)
341→	if errors.Is(err, pgx.ErrNoRows) {
342→		return nil, fmt.Errorf("item: update: not found")
343→	}
344→	if err != nil {
345→		return nil, fmt.Errorf("item: update: %w", err)
346→	}
347→	return it, nil
348→}
