350→// Delete removes an item by ID and owner. Returns an error if not found.
351→func (s *Service) Delete(ctx context.Context, ownerID, itemID uuid.UUID) error {
352→	tag, err := s.pool.Exec(ctx,
353→		"DELETE FROM items WHERE owner_id = $1 AND id = $2",
354→		ownerID, itemID)
355→	if err != nil {
356→		return fmt.Errorf("item: delete: %w", err)
357→	}
358→	if tag.RowsAffected() == 0 {
359→		return fmt.Errorf("item: delete: not found")
360→	}
361→	return nil
362→}
