395→// ContentUpdate holds fields that background workers set after processing an item.
396→type ContentUpdate struct {
397→	Status      string
398→	Title       *string
399→	ContentText *string
400→	ContentURL  *string
401→}
402→
403→// UpdateContent updates worker-managed fields (status, title, content) on an item.
404→// This is used by background jobs, not exposed via GraphQL.
405→func (s *Service) UpdateContent(ctx context.Context, itemID uuid.UUID, input ContentUpdate) error {
406→	sets := []string{fmt.Sprintf("status = $%d", 2)}
407→	args := []any{itemID, input.Status}
408→	paramIdx := 3
409→
410→	if input.Title != nil {
411→		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
412→		args = append(args, *input.Title)
413→		paramIdx++
414→	}
415→	if input.ContentText != nil {
416→		sets = append(sets, fmt.Sprintf("content_text = $%d", paramIdx))
417→		args = append(args, *input.ContentText)
418→		paramIdx++
419→	}
420→	if input.ContentURL != nil {
421→		sets = append(sets, fmt.Sprintf("content_url = $%d", paramIdx))
422→		args = append(args, *input.ContentURL)
423→		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
424→	}
425→
426→	query := fmt.Sprintf(`UPDATE items SET %s WHERE id = $1`, joinSets(sets))
427→	tag, err := s.pool.Exec(ctx, query, args...)
428→	if err != nil {
429→		return fmt.Errorf("item: update content: %w", err)
430→	}
431→	if tag.RowsAffected() == 0 {
432→		return fmt.Errorf("item: update content: not found")
433→	}
434→	return nil
435→}
436→
437→func joinSets(sets []string) string {
438→	result := ""
439→	for i, s := range sets {
440→		if i > 0 {
441→			result += ", "
442→		}
443→		result += s
444→	}
445→	return result
446→}
