package item

import (
	"context"
	"testing"
)

func TestCaptureBookmarkValidation(t *testing.T) {
	svc := New(nil) // pool is nil — we only test validation, not DB calls

	t.Run("empty URL returns error", func(t *testing.T) {
		_, err := svc.CaptureBookmark(context.TODO(), [16]byte{}, BookmarkInput{URL: ""})
		if err == nil {
			t.Fatal("expected error for empty URL")
		}
	})
}

func TestCaptureNoteValidation(t *testing.T) {
	svc := New(nil)

	t.Run("empty content returns error", func(t *testing.T) {
		_, err := svc.CaptureNote(context.TODO(), [16]byte{}, NoteInput{Content: ""})
		if err == nil {
			t.Fatal("expected error for empty content")
		}
	})
}

func TestBookmarkInputDefaults(t *testing.T) {
	input := BookmarkInput{URL: "https://example.com"}

	// Test that empty source gets default
	if input.Source != "" {
		t.Errorf("expected empty source before default, got %q", input.Source)
	}

	// The service applies defaults — test the logic
	if input.Source == "" {
		input.Source = "api"
	}
	if input.Source != "api" {
		t.Errorf("expected source 'api', got %q", input.Source)
	}

	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}
	if input.Sensitivity != "normal" {
		t.Errorf("expected sensitivity 'normal', got %q", input.Sensitivity)
	}
}

func TestNoteInputDefaults(t *testing.T) {
	input := NoteInput{Content: "hello"}

	if input.Source == "" {
		input.Source = "api"
	}
	if input.Source != "api" {
		t.Errorf("expected source 'api', got %q", input.Source)
	}

	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}
	if input.Sensitivity != "normal" {
		t.Errorf("expected sensitivity 'normal', got %q", input.Sensitivity)
	}
}

func TestSearchEmptyQuery(t *testing.T) {
	svc := New(nil)

	result, err := svc.Search(context.TODO(), [16]byte{}, "", nil, 20, 0.0)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(result.Items) != 0 {
		t.Errorf("expected 0 items for empty query, got %d", len(result.Items))
	}
}

func TestSemanticSearchEmptyEmbedding(t *testing.T) {
	svc := New(nil)

	result, err := svc.SemanticSearch(context.TODO(), [16]byte{}, nil, nil, 20, 0.5)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(result.Items) != 0 {
		t.Errorf("expected 0 items for empty embedding, got %d", len(result.Items))
	}
}

func TestSemanticSearchEmptySlice(t *testing.T) {
	svc := New(nil)

	result, err := svc.SemanticSearch(context.TODO(), [16]byte{}, []float32{}, nil, 20, 0.5)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(result.Items) != 0 {
		t.Errorf("expected 0 items for empty embedding, got %d", len(result.Items))
	}
}

func TestBuildBookmarkMetadata(t *testing.T) {
	sel := "selected text"
	ref := "https://referrer.example.com"

	t.Run("both selection and referrer", func(t *testing.T) {
		m := buildBookmarkMetadata(&sel, &ref)
		if m["selection"] != sel {
			t.Errorf("expected selection %q, got %v", sel, m["selection"])
		}
		if m["referrer"] != ref {
			t.Errorf("expected referrer %q, got %v", ref, m["referrer"])
		}
	})

	t.Run("selection only", func(t *testing.T) {
		m := buildBookmarkMetadata(&sel, nil)
		if m["selection"] != sel {
			t.Errorf("expected selection %q, got %v", sel, m["selection"])
		}
		if _, ok := m["referrer"]; ok {
			t.Error("expected no referrer key")
		}
	})

	t.Run("referrer only", func(t *testing.T) {
		m := buildBookmarkMetadata(nil, &ref)
		if _, ok := m["selection"]; ok {
			t.Error("expected no selection key")
		}
		if m["referrer"] != ref {
			t.Errorf("expected referrer %q, got %v", ref, m["referrer"])
		}
	})

	t.Run("neither", func(t *testing.T) {
		m := buildBookmarkMetadata(nil, nil)
		if len(m) != 0 {
			t.Errorf("expected empty metadata, got %v", m)
		}
	})

	t.Run("empty strings treated as absent", func(t *testing.T) {
		empty := ""
		m := buildBookmarkMetadata(&empty, &empty)
		if len(m) != 0 {
			t.Errorf("expected empty metadata for empty strings, got %v", m)
		}
	})
}

func TestJoinSets(t *testing.T) {
	tests := []struct {
		sets []string
		want string
	}{
		{nil, ""},
		{[]string{}, ""},
		{[]string{"a = $1"}, "a = $1"},
		{[]string{"a = $1", "b = $2"}, "a = $1, b = $2"},
		{[]string{"a = $1", "b = $2", "c = $3"}, "a = $1, b = $2, c = $3"},
	}
	for _, tt := range tests {
		if got := joinSets(tt.sets); got != tt.want {
			t.Errorf("joinSets(%v) = %q, want %q", tt.sets, got, tt.want)
		}
	}
}

package user

import (
	"context"
	"errors"
	"fmt"
	"strings"
	"time"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgconn"
	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/ketang/flotsam/api/internal/auth"
)

// ErrEmailTaken is returned when a registration uses an already-taken email.
var ErrEmailTaken = errors.New("user: email already taken")

// ErrNotFound is returned when a user lookup finds no matching row.
var ErrNotFound = errors.New("user: not found")

// User represents a row in the users table.
type User struct {
	ID           uuid.UUID
	Email        string
	DisplayName  *string
	PasswordHash *string
	AuthProvider string
	Settings     map[string]any
	CreatedAt    time.Time
	UpdatedAt    time.Time
}

// userColumns is the canonical SELECT column list for the users table.
const userColumns = `id, email, display_name, password_hash, auth_provider, settings, created_at, updated_at`

// Service provides user CRUD operations.
type Service struct {
	pool *pgxpool.Pool
}

// New creates a new user Service.
func New(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// Create registers a new local user with email/password authentication.
func (s *Service) Create(ctx context.Context, email, password, displayName string) (*User, error) {
	email = strings.TrimSpace(strings.ToLower(email))
	if !strings.Contains(email, "@") || email == "" {
		return nil, fmt.Errorf("user: create: invalid email")
	}
	if len(password) < 8 {
		return nil, fmt.Errorf("user: create: password must be at least 8 characters")
	}

	hash, err := auth.HashPassword(password)
	if err != nil {
		return nil, fmt.Errorf("user: create: %w", err)
	}

	var dn *string
	if displayName != "" {
		displayName = strings.TrimSpace(displayName)
		dn = &displayName
	}

	query := fmt.Sprintf(`INSERT INTO users (email, display_name, password_hash, auth_provider)
		VALUES ($1, $2, $3, 'local')
		RETURNING %s`, userColumns)

	row := s.pool.QueryRow(ctx, query, email, dn, hash)
	u, err := scanUser(row)
	if err != nil {
		var pgErr *pgconn.PgError
		if errors.As(err, &pgErr) && pgErr.Code == "23505" {
			return nil, ErrEmailTaken
		}
		return nil, fmt.Errorf("user: create: %w", err)
	}
	return u, nil
}

// GetByEmail returns a user by email. Returns nil, nil if not found.
func (s *Service) GetByEmail(ctx context.Context, email string) (*User, error) {
	email = strings.TrimSpace(strings.ToLower(email))
	query := fmt.Sprintf(`SELECT %s FROM users WHERE email = $1`, userColumns)
	row := s.pool.QueryRow(ctx, query, email)
	u, err := scanUser(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("user: get by email: %w", err)
	}
	return u, nil
}

// GetByID returns a user by ID. Returns nil, nil if not found.
func (s *Service) GetByID(ctx context.Context, id uuid.UUID) (*User, error) {
	query := fmt.Sprintf(`SELECT %s FROM users WHERE id = $1`, userColumns)
	row := s.pool.QueryRow(ctx, query, id)
	u, err := scanUser(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("user: get by id: %w", err)
	}
	return u, nil
}

// scanUser scans a single user row.
func scanUser(row pgx.Row) (*User, error) {
	var u User
	err := row.Scan(
		&u.ID,
		&u.Email,
		&u.DisplayName,
		&u.PasswordHash,
		&u.AuthProvider,
		&u.Settings,
		&u.CreatedAt,
		&u.UpdatedAt,
	)
	if err != nil {
		return nil, err
	}
	return &u, nil
}

