package user

import (
	"context"
	"os"
	"testing"

	"github.com/google/uuid"

	"github.com/ketang/flotsam/api/internal/db"
)

func setupTestDB(t *testing.T) *Service {
	t.Helper()
	if testing.Short() {
		t.Skip("skipping integration test")
	}
	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		t.Skip("DATABASE_URL not set")
	}
	ctx := context.Background()
	pool, err := db.Connect(ctx, dbURL)
	if err != nil {
		t.Fatalf("db.Connect() error = %v", err)
	}
	t.Cleanup(func() { pool.Close() })
	return New(pool)
}

func TestIntegrationCreate(t *testing.T) {
	svc := setupTestDB(t)
	ctx := context.Background()

	email := "test-" + uuid.New().String()[:8] + "@example.com"
	u, err := svc.Create(ctx, email, "password123", "Test User")
	if err != nil {
		t.Fatalf("Create() error = %v", err)
	}
	if u.Email != email {
		t.Errorf("Email = %q, want %q", u.Email, email)
	}
	if u.DisplayName == nil || *u.DisplayName != "Test User" {
		t.Errorf("DisplayName = %v, want 'Test User'", u.DisplayName)
	}
	if u.AuthProvider != "local" {
		t.Errorf("AuthProvider = %q, want 'local'", u.AuthProvider)
	}
	if u.ID == uuid.Nil {
		t.Error("ID should not be nil")
	}

	// Cleanup
	_, _ = svc.pool.Exec(ctx, "DELETE FROM users WHERE id = $1", u.ID)
}

func TestIntegrationCreate_DuplicateEmail(t *testing.T) {
	svc := setupTestDB(t)
	ctx := context.Background()

	email := "dup-" + uuid.New().String()[:8] + "@example.com"
	u, err := svc.Create(ctx, email, "password123", "")
	if err != nil {
		t.Fatalf("Create() error = %v", err)
	}
	defer func() { _, _ = svc.pool.Exec(ctx, "DELETE FROM users WHERE id = $1", u.ID) }()

	_, err = svc.Create(ctx, email, "password456", "")
	if err != ErrEmailTaken {
		t.Errorf("Create() duplicate error = %v, want ErrEmailTaken", err)
	}
}

func TestIntegrationGetByEmail(t *testing.T) {
	svc := setupTestDB(t)
	ctx := context.Background()

	email := "getby-" + uuid.New().String()[:8] + "@example.com"
	created, err := svc.Create(ctx, email, "password123", "")
	if err != nil {
		t.Fatalf("Create() error = %v", err)
	}
	defer func() { _, _ = svc.pool.Exec(ctx, "DELETE FROM users WHERE id = $1", created.ID) }()

	found, err := svc.GetByEmail(ctx, email)
	if err != nil {
		t.Fatalf("GetByEmail() error = %v", err)
	}
	if found == nil {
		t.Fatal("GetByEmail() returned nil")
	}
	if found.ID != created.ID {
		t.Errorf("ID = %v, want %v", found.ID, created.ID)
	}
}

func TestIntegrationGetByEmail_NotFound(t *testing.T) {
	svc := setupTestDB(t)
	ctx := context.Background()

	u, err := svc.GetByEmail(ctx, "nonexistent@example.com")
	if err != nil {
		t.Fatalf("GetByEmail() error = %v", err)
	}
	if u != nil {
		t.Errorf("GetByEmail() = %v, want nil", u)
	}
}

func TestIntegrationGetByID(t *testing.T) {
	svc := setupTestDB(t)
	ctx := context.Background()

	email := "byid-" + uuid.New().String()[:8] + "@example.com"
	created, err := svc.Create(ctx, email, "password123", "")
	if err != nil {
		t.Fatalf("Create() error = %v", err)
	}
	defer func() { _, _ = svc.pool.Exec(ctx, "DELETE FROM users WHERE id = $1", created.ID) }()

	found, err := svc.GetByID(ctx, created.ID)
	if err != nil {
		t.Fatalf("GetByID() error = %v", err)
	}
	if found == nil {
		t.Fatal("GetByID() returned nil")
	}
	if found.Email != email {
		t.Errorf("Email = %q, want %q", found.Email, email)
	}
}

func TestIntegrationGetByID_NotFound(t *testing.T) {
	svc := setupTestDB(t)
	ctx := context.Background()

	u, err := svc.GetByID(ctx, uuid.New())
	if err != nil {
		t.Fatalf("GetByID() error = %v", err)
	}
	if u != nil {
		t.Errorf("GetByID() = %v, want nil", u)
	}
}

func TestCreate_ValidationErrors(t *testing.T) {
	// These don't need a DB — they fail before any SQL
	svc := &Service{} // nil pool is fine; we won't reach it

	tests := []struct {
		name     string
		email    string
		password string
		wantErr  string
	}{
		{"empty email", "", "password123", "invalid email"},
		{"no at sign", "notanemail", "password123", "invalid email"},
		{"short password", "a@b.com", "short", "at least 8"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := svc.Create(context.Background(), tt.email, tt.password, "")
			if err == nil {
				t.Fatal("expected error")
			}
			if !containsStr(err.Error(), tt.wantErr) {
				t.Errorf("error = %q, want to contain %q", err.Error(), tt.wantErr)
			}
		})
	}
}

func containsStr(s, substr string) bool {
	return len(s) >= len(substr) && containsSubstring(s, substr)
}

func containsSubstring(s, sub string) bool {
	for i := 0; i <= len(s)-len(sub); i++ {
		if s[i:i+len(sub)] == sub {
			return true
		}
	}
	return false
}

