package audit

import (
	"testing"

	"github.com/google/uuid"
)

func TestEntryFields(t *testing.T) {
	userID := uuid.New()
	clientID := uuid.New()
	approved := true

	e := Entry{
		UserID:       userID,
		ClientID:     &clientID,
		Action:       "mcp.search",
		ResourceType: "item",
		ResourceID:   nil,
		Request:      map[string]any{"query": "test"},
		Approved:     &approved,
	}

	if e.UserID != userID {
		t.Errorf("expected user ID %v, got %v", userID, e.UserID)
	}
	if *e.ClientID != clientID {
		t.Errorf("expected client ID %v, got %v", clientID, *e.ClientID)
	}
	if e.Action != "mcp.search" {
		t.Errorf("expected action mcp.search, got %s", e.Action)
	}
	if *e.Approved != true {
		t.Error("expected approved to be true")
	}
}

func TestNew(t *testing.T) {
	// New should accept nil pool (used in unit tests where DB is unavailable)
	logger := New(nil)
	if logger == nil {
		t.Fatal("expected non-nil logger")
	}
}

