}

func (S3UploadArgs) Kind() string { return "s3_upload" }

// S3UploadWorker uploads large content to S3.
type S3UploadWorker struct {
	river.WorkerDefaults[S3UploadArgs]
}

func (w *S3UploadWorker) Work(ctx context.Context, job *river.Job[S3UploadArgs]) error {
	slog.InfoContext(ctx, "worker: s3_upload: processing",
