package mcpclient

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"time"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
)

const (
	// apiKeyPrefix identifies Flotsam API keys for humans and secret scanners.
	apiKeyPrefix = "flt_"
	// apiKeyBytes is the number of random bytes in an API key (256-bit).
	apiKeyBytes = 32
)

// ErrNotFound is returned when a client lookup finds no matching row.
var ErrNotFound = errors.New("mcpclient: not found")

// clientColumns is the canonical SELECT column list for the mcp_clients table.
const clientColumns = `id, owner_id, name, api_key_hash, permissions, requires_approval, active, last_used_at, created_at`

// Service provides MCP client CRUD operations.
type Service struct {
	pool *pgxpool.Pool
}

// New creates a new MCP client Service.
func New(pool *pgxpool.Pool) *Service {
	return &Service{pool: pool}
}

// Create registers a new MCP client for the given owner. Returns the client and
// the plaintext API key (shown only once; stored as SHA-256 hash).
func (s *Service) Create(ctx context.Context, ownerID uuid.UUID, name string, perms Permissions) (*Client, string, error) {
	if name == "" {
		return nil, "", fmt.Errorf("mcpclient: create: name is required")
	}

	plainKey, hash, err := generateAPIKey()
	if err != nil {
		return nil, "", fmt.Errorf("mcpclient: create: %w", err)
	}

	permsJSON, err := json.Marshal(perms)
	if err != nil {
		return nil, "", fmt.Errorf("mcpclient: create: marshal permissions: %w", err)
	}

	query := fmt.Sprintf(`INSERT INTO mcp_clients (owner_id, name, api_key_hash, permissions)
		VALUES ($1, $2, $3, $4)
		RETURNING %s`, clientColumns)

	row := s.pool.QueryRow(ctx, query, ownerID, name, hash, permsJSON)
	c, err := scanClient(row)
	if err != nil {
		return nil, "", fmt.Errorf("mcpclient: create: %w", err)
	}
	return c, plainKey, nil
}

// GetByID returns a client by its ID. Returns ErrNotFound if not found.
func (s *Service) GetByID(ctx context.Context, id uuid.UUID) (*Client, error) {
	query := fmt.Sprintf(`SELECT %s FROM mcp_clients WHERE id = $1`, clientColumns)
	row := s.pool.QueryRow(ctx, query, id)
	c, err := scanClient(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, fmt.Errorf("mcpclient: get by id: %w", err)
	}
	return c, nil
}

// GetByAPIKey looks up an active client by API key hash. Returns ErrNotFound if
// no active client matches. The caller must hash the plaintext key with HashAPIKey.
func (s *Service) GetByAPIKey(ctx context.Context, keyHash string) (*Client, error) {
	query := fmt.Sprintf(`SELECT %s FROM mcp_clients WHERE api_key_hash = $1 AND active = true`, clientColumns)
	row := s.pool.QueryRow(ctx, query, keyHash)
	c, err := scanClient(row)
	if errors.Is(err, pgx.ErrNoRows) {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, fmt.Errorf("mcpclient: get by api key: %w", err)
	}
	return c, nil
}

// ListByOwner returns all clients owned by the given user.
func (s *Service) ListByOwner(ctx context.Context, ownerID uuid.UUID) ([]*Client, error) {
	query := fmt.Sprintf(`SELECT %s FROM mcp_clients WHERE owner_id = $1 ORDER BY created_at DESC`, clientColumns)
	rows, err := s.pool.Query(ctx, query, ownerID)
	if err != nil {
		return nil, fmt.Errorf("mcpclient: list by owner: %w", err)
	}
	defer rows.Close()

	var clients []*Client
	for rows.Next() {
		c, err := scanClient(rows)
		if err != nil {
			return nil, fmt.Errorf("mcpclient: list by owner: scan: %w", err)
		}
		clients = append(clients, c)
	}
	return clients, rows.Err()
}

// Deactivate sets a client's active flag to false.
func (s *Service) Deactivate(ctx context.Context, id uuid.UUID) error {
	query := `UPDATE mcp_clients SET active = false WHERE id = $1`
	tag, err := s.pool.Exec(ctx, query, id)
	if err != nil {
		return fmt.Errorf("mcpclient: deactivate: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return ErrNotFound
	}
	return nil
}

// TouchLastUsed updates the last_used_at timestamp. Errors are logged but not returned.
func (s *Service) TouchLastUsed(ctx context.Context, id uuid.UUID) {
	query := `UPDATE mcp_clients SET last_used_at = $1 WHERE id = $2`
	if _, err := s.pool.Exec(ctx, query, time.Now(), id); err != nil {
		slog.ErrorContext(ctx, "mcpclient: touch last used", "client_id", id, "error", err)
	}
}

// HashAPIKey computes the SHA-256 hash of a plaintext API key, returning the hex digest.
func HashAPIKey(plainKey string) string {
	h := sha256.Sum256([]byte(plainKey))
	return hex.EncodeToString(h[:])
}

// generateAPIKey creates a new API key with the flt_ prefix and its SHA-256 hash.
func generateAPIKey() (plain, hash string, err error) {
	b := make([]byte, apiKeyBytes)
	if _, err := rand.Read(b); err != nil {
		return "", "", fmt.Errorf("generate api key: %w", err)
	}
	plain = apiKeyPrefix + base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(b)
	hash = HashAPIKey(plain)
	return plain, hash, nil
}

// scanClient scans a single client row.
func scanClient(row pgx.Row) (*Client, error) {
	var c Client
	var permsJSON []byte
	err := row.Scan(
		&c.ID,
		&c.OwnerID,
		&c.Name,
		&c.APIKeyHash,
		&permsJSON,
		&c.RequiresApproval,
		&c.Active,
		&c.LastUsedAt,
		&c.CreatedAt,
	)
	if err != nil {
		return nil, err
	}
	if err := json.Unmarshal(permsJSON, &c.Permissions); err != nil {
		return nil, fmt.Errorf("mcpclient: unmarshal permissions: %w", err)
	}
	return &c, nil
}

