package mcpclient

import (
	"strings"
	"testing"
)

func TestHashAPIKey_Deterministic(t *testing.T) {
	key := "flt_test1234567890"
	hash1 := HashAPIKey(key)
	hash2 := HashAPIKey(key)
	if hash1 != hash2 {
		t.Error("HashAPIKey should be deterministic")
	}
}

func TestHashAPIKey_DifferentKeys(t *testing.T) {
	hash1 := HashAPIKey("flt_key1")
	hash2 := HashAPIKey("flt_key2")
	if hash1 == hash2 {
		t.Error("different keys should produce different hashes")
	}
}

func TestHashAPIKey_HexEncoded(t *testing.T) {
	hash := HashAPIKey("flt_test")
	if len(hash) != 64 { // SHA-256 hex = 64 chars
		t.Errorf("expected 64-char hex hash, got %d chars", len(hash))
	}
}

func TestGenerateAPIKey_Format(t *testing.T) {
	plain, hash, err := generateAPIKey()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !strings.HasPrefix(plain, "flt_") {
		t.Errorf("expected flt_ prefix, got %q", plain)
	}
	if hash == "" {
		t.Error("hash should not be empty")
	}
	if HashAPIKey(plain) != hash {
		t.Error("hash should match HashAPIKey(plain)")
	}
}

func TestGenerateAPIKey_Unique(t *testing.T) {
	plain1, _, _ := generateAPIKey()
	plain2, _, _ := generateAPIKey()
	if plain1 == plain2 {
		t.Error("generated keys should be unique")
	}
}

func TestClient_HasTool(t *testing.T) {
	c := &Client{
		Permissions: Permissions{
			Tools: []string{"search", "browse"},
		},
	}

	if !c.HasTool("search") {
		t.Error("expected HasTool(search) = true")
	}
	if !c.HasTool("browse") {
		t.Error("expected HasTool(browse) = true")
	}
	if c.HasTool("capture") {
		t.Error("expected HasTool(capture) = false")
	}
}

func TestClient_HasTool_EmptyList(t *testing.T) {
	c := &Client{
		Permissions: Permissions{Tools: nil},
	}
	if c.HasTool("search") {
		t.Error("nil tools should not match anything")
	}
}

func TestNew(t *testing.T) {
	svc := New(nil)
	if svc == nil {
		t.Fatal("expected non-nil service")
	}
}

package worker

import (
	"context"
	"fmt"
	"log/slog"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5/pgxpool"
	pgvector "github.com/pgvector/pgvector-go"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/provider"
)

// EmbedArgs are the arguments for an embedding generation job.
type EmbedArgs struct {
	ItemID  uuid.UUID `json:"item_id"`
	Content string    `json:"content"`
}

func (EmbedArgs) Kind() string { return "embed" }

// EmbedWorker generates vector embeddings for item content.
type EmbedWorker struct {
	river.WorkerDefaults[EmbedArgs]
	Pool     *pgxpool.Pool
	Embedder provider.Embedder
}

func (w *EmbedWorker) Work(ctx context.Context, job *river.Job[EmbedArgs]) error {
	slog.InfoContext(ctx, "worker: embed: processing",
		"item_id", job.Args.ItemID,
		"content_len", len(job.Args.Content),
	)

	if w.Embedder == nil {
		slog.WarnContext(ctx, "worker: embed: no embedder configured, skipping",
			"item_id", job.Args.ItemID,
		)
		return nil
	}

	if job.Args.Content == "" {
		slog.WarnContext(ctx, "worker: embed: empty content, skipping",
			"item_id", job.Args.ItemID,
		)
		return nil
	}

	// Generate embedding
	embedding, err := w.Embedder.Embed(ctx, job.Args.Content)
	if err != nil {
		return fmt.Errorf("worker: embed: generate embedding: %w", err)
	}

	// Store embedding in database
	vec := pgvector.NewVector(embedding)
	_, err = w.Pool.Exec(ctx,
		`UPDATE items SET embedding = $1, updated_at = now() WHERE id = $2`,
		vec, job.Args.ItemID)
	if err != nil {
		return fmt.Errorf("worker: embed: store embedding: %w", err)
	}

	slog.InfoContext(ctx, "worker: embed: done",
		"item_id", job.Args.ItemID,
		"dimensions", len(embedding),
	)
	return nil
}

