package worker

import (
	"context"
	"encoding/json"
	"fmt"
	"testing"

	"github.com/google/uuid"
	"github.com/riverqueue/river"
)

// mockEmbedder is a test double for provider.Embedder.
type mockEmbedder struct {
	embedding  []float32
	err        error
	callCount  int
	lastInput  string
}

func (m *mockEmbedder) Embed(_ context.Context, text string) ([]float32, error) {
	m.callCount++
	m.lastInput = text
	return m.embedding, m.err
}

func (m *mockEmbedder) Dimensions() int { return 1536 }

func TestEmbedWorker_NilEmbedder(t *testing.T) {
	w := &EmbedWorker{Pool: nil, Embedder: nil}
	job := &river.Job[EmbedArgs]{
		Args: EmbedArgs{
			ItemID:  uuid.New(),
			Content: "hello world",
		},
	}
	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("expected nil error when embedder is nil, got: %v", err)
	}
}

func TestEmbedWorker_EmptyContent(t *testing.T) {
	embedder := &mockEmbedder{embedding: make([]float32, 1536)}
	w := &EmbedWorker{Pool: nil, Embedder: embedder}
	job := &river.Job[EmbedArgs]{
		Args: EmbedArgs{
			ItemID:  uuid.New(),
			Content: "",
		},
	}
	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("expected nil error for empty content, got: %v", err)
	}
	if embedder.callCount != 0 {
		t.Errorf("expected no embed calls for empty content, got %d", embedder.callCount)
	}
}

func TestEmbedWorker_EmbedError(t *testing.T) {
	embedder := &mockEmbedder{err: fmt.Errorf("api error")}
	w := &EmbedWorker{Pool: nil, Embedder: embedder}
	job := &river.Job[EmbedArgs]{
		Args: EmbedArgs{
			ItemID:  uuid.New(),
			Content: "some content",
		},
	}
	err := w.Work(context.Background(), job)
	if err == nil {
		t.Fatal("expected error when embedder fails")
	}
	if embedder.callCount != 1 {
		t.Errorf("expected 1 embed call, got %d", embedder.callCount)
	}
}

func TestEmbedWorker_SuccessfulEmbed_NilPool(t *testing.T) {
	// When the embedder succeeds but the pool is nil, the DB write panics.
	// This verifies the embedder is called with the correct input and the
	// error path through the DB layer is exercised.
	embedder := &mockEmbedder{embedding: []float32{0.1, 0.2, 0.3}}
	w := &EmbedWorker{Pool: nil, Embedder: embedder}
	job := &river.Job[EmbedArgs]{
		Args: EmbedArgs{
			ItemID:  uuid.New(),
			Content: "test content for embedding",
		},
	}

	// Pool is nil so the DB Exec will panic — recover and verify the embedder was called
	func() {
		defer func() {
			if r := recover(); r == nil {
				t.Fatal("expected panic from nil pool Exec, got none")
			}
		}()
		_ = w.Work(context.Background(), job)
	}()

	if embedder.callCount != 1 {
		t.Errorf("expected 1 embed call, got %d", embedder.callCount)
	}
	if embedder.lastInput != "test content for embedding" {
		t.Errorf("embedder received %q, want %q", embedder.lastInput, "test content for embedding")
	}
}

func TestEmbedArgs_Kind(t *testing.T) {
	args := EmbedArgs{}
	if args.Kind() != "embed" {
		t.Errorf("expected kind 'embed', got %q", args.Kind())
	}
}

func TestEmbedArgs_JSONRoundTrip(t *testing.T) {
	itemID := uuid.New()
	args := EmbedArgs{
		ItemID:  itemID,
		Content: "some text to embed",
	}

	data, err := json.Marshal(args)
	if err != nil {
		t.Fatalf("Marshal: %v", err)
	}

	var decoded EmbedArgs
	if err := json.Unmarshal(data, &decoded); err != nil {
		t.Fatalf("Unmarshal: %v", err)
	}

	if decoded.ItemID != itemID {
		t.Errorf("ItemID = %v, want %v", decoded.ItemID, itemID)
	}
	if decoded.Content != "some text to embed" {
		t.Errorf("Content = %q, want %q", decoded.Content, "some text to embed")
	}
}

