			ItemID: uuid.New(),
			URL:    srv.URL,
		},
	}

	err := w.Work(context.Background(), job)
	if err == nil {
		t.Fatal("Work() should return error for 404")
	}

	// Should have set processing then error
	if len(items.updates) != 2 {
		t.Fatalf("expected 2 UpdateContent calls, got %d", len(items.updates))
	}
	if items.updates[1].Status != "error" {
		t.Errorf("error update status = %q, want %q", items.updates[1].Status, "error")
	}
