package worker

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/provider"
)

// ClassifyArgs are the arguments for an auto-classification job.
type ClassifyArgs struct {
	ItemID  uuid.UUID `json:"item_id"`
	Content string    `json:"content"`
}

func (ClassifyArgs) Kind() string { return "classify" }

// ClassifyWorker auto-extracts metadata (category, people, topics) via LLM.
type ClassifyWorker struct {
	river.WorkerDefaults[ClassifyArgs]
	Classifier provider.Classifier
	Pool       *pgxpool.Pool
}

func (w *ClassifyWorker) Work(ctx context.Context, job *river.Job[ClassifyArgs]) error {
	slog.InfoContext(ctx, "worker: classify: processing",
		"item_id", job.Args.ItemID,
		"content_len", len(job.Args.Content),
	)

	if w.Classifier == nil {
		slog.WarnContext(ctx, "worker: classify: no classifier configured, skipping",
			"item_id", job.Args.ItemID,
		)
		return nil
	}

	if job.Args.Content == "" {
		slog.WarnContext(ctx, "worker: classify: empty content, skipping",
			"item_id", job.Args.ItemID,
		)
		return nil
	}

	classification, err := w.Classifier.Classify(ctx, job.Args.Content)
	if err != nil {
		return fmt.Errorf("worker: classify: classify content: %w", err)
	}

	// Convert Classification to map for JSONB storage
	metadataJSON, err := json.Marshal(classification)
	if err != nil {
		return fmt.Errorf("worker: classify: marshal metadata: %w", err)
	}

	_, err = w.Pool.Exec(ctx,
		`UPDATE items SET auto_metadata = $1, updated_at = now() WHERE id = $2`,
		metadataJSON, job.Args.ItemID)
	if err != nil {
		return fmt.Errorf("worker: classify: store metadata: %w", err)
	}

	slog.InfoContext(ctx, "worker: classify: done",
		"item_id", job.Args.ItemID,
		"category", classification.Category,
		"topics", classification.Topics,
	)
	return nil
}

