package worker

import (
	"context"
	"encoding/json"
	"fmt"
	"testing"

	"github.com/google/uuid"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/provider"
)

// mockClassifier is a test double for provider.Classifier.
type mockClassifier struct {
	result    *provider.Classification
	err       error
	callCount int
	lastInput string
}

func (m *mockClassifier) Classify(_ context.Context, content string) (*provider.Classification, error) {
	m.callCount++
	m.lastInput = content
	return m.result, m.err
}

func TestClassifyWorker_NilClassifier(t *testing.T) {
	w := &ClassifyWorker{Classifier: nil, Pool: nil}
	job := &river.Job[ClassifyArgs]{
		Args: ClassifyArgs{
			ItemID:  uuid.New(),
			Content: "hello world",
		},
	}
	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("expected nil error when classifier is nil, got: %v", err)
	}
}

func TestClassifyWorker_EmptyContent(t *testing.T) {
	classifier := &mockClassifier{
		result: &provider.Classification{Category: "test"},
	}
	w := &ClassifyWorker{Classifier: classifier, Pool: nil}
	job := &river.Job[ClassifyArgs]{
		Args: ClassifyArgs{
			ItemID:  uuid.New(),
			Content: "",
		},
	}
	err := w.Work(context.Background(), job)
	if err != nil {
		t.Fatalf("expected nil error for empty content, got: %v", err)
	}
	if classifier.callCount != 0 {
		t.Errorf("expected no classify calls for empty content, got %d", classifier.callCount)
	}
}

func TestClassifyWorker_ClassifyError(t *testing.T) {
	classifier := &mockClassifier{err: fmt.Errorf("api error")}
	w := &ClassifyWorker{Classifier: classifier, Pool: nil}
	job := &river.Job[ClassifyArgs]{
		Args: ClassifyArgs{
			ItemID:  uuid.New(),
			Content: "some content",
		},
	}
	err := w.Work(context.Background(), job)
	if err == nil {
		t.Fatal("expected error when classifier fails")
	}
	if classifier.callCount != 1 {
		t.Errorf("expected 1 classify call, got %d", classifier.callCount)
	}
}

func TestClassifyWorker_SuccessfulClassify_NilPool(t *testing.T) {
	// When the classifier succeeds but the pool is nil, the DB write panics.
	// This verifies the classifier is called with the correct input.
	classifier := &mockClassifier{
		result: &provider.Classification{
			Category: "technology",
			Topics:   []string{"go", "testing"},
		},
	}
	w := &ClassifyWorker{Classifier: classifier, Pool: nil}
	job := &river.Job[ClassifyArgs]{
		Args: ClassifyArgs{
			ItemID:  uuid.New(),
			Content: "article about Go testing",
		},
	}

	// Pool is nil so the DB Exec will panic — recover and verify the classifier was called
	func() {
		defer func() {
			if r := recover(); r == nil {
				t.Fatal("expected panic from nil pool Exec, got none")
			}
		}()
		_ = w.Work(context.Background(), job)
	}()

	if classifier.callCount != 1 {
		t.Errorf("expected 1 classify call, got %d", classifier.callCount)
	}
	if classifier.lastInput != "article about Go testing" {
		t.Errorf("classifier received %q, want %q", classifier.lastInput, "article about Go testing")
	}
}

func TestClassifyArgs_Kind(t *testing.T) {
	args := ClassifyArgs{}
	if args.Kind() != "classify" {
		t.Errorf("expected kind 'classify', got %q", args.Kind())
	}
}

func TestClassifyArgs_JSONRoundTrip(t *testing.T) {
	itemID := uuid.New()
	args := ClassifyArgs{
		ItemID:  itemID,
		Content: "content to classify",
	}

	data, err := json.Marshal(args)
	if err != nil {
		t.Fatalf("Marshal: %v", err)
	}

	var decoded ClassifyArgs
	if err := json.Unmarshal(data, &decoded); err != nil {
		t.Fatalf("Unmarshal: %v", err)
	}

	if decoded.ItemID != itemID {
		t.Errorf("ItemID = %v, want %v", decoded.ItemID, itemID)
	}
	if decoded.Content != "content to classify" {
		t.Errorf("Content = %q, want %q", decoded.Content, "content to classify")
	}
}

