package storage

import (
	"fmt"
	"strings"

	"github.com/google/uuid"
)

// KeyFor generates the S3 key for an item's content.
// Pattern: {owner_id}/{type}/{item_id}/{filename}
func KeyFor(ownerID uuid.UUID, itemType string, itemID uuid.UUID, filename string) string {
	return fmt.Sprintf("%s/%s/%s/%s", ownerID, itemType, itemID, filename)
}

// BookmarkKey returns the key for a bookmark's fetched HTML content.
func BookmarkKey(ownerID, itemID uuid.UUID) string {
	return KeyFor(ownerID, "bookmarks", itemID, "content.html")
}

// AudioKey returns the key for a voice note's audio file.
func AudioKey(ownerID, itemID uuid.UUID, format string) string {
	return KeyFor(ownerID, "voice_notes", itemID, "audio."+format)
}

// FileKey returns the key for a generic file upload.
func FileKey(ownerID, itemID uuid.UUID, filename string) string {
	return KeyFor(ownerID, "files", itemID, filename)
}

// ValidateKeyOwnership checks that an S3 key belongs to the given owner.
// Keys must start with "{ownerID}/" and must not contain path traversal sequences.
func ValidateKeyOwnership(key string, ownerID uuid.UUID) error {
	if key == "" {
		return fmt.Errorf("storage: key is empty")
	}
	if strings.Contains(key, "..") {
		return fmt.Errorf("storage: key contains path traversal")
	}
	prefix := ownerID.String() + "/"
	if !strings.HasPrefix(key, prefix) {
		return fmt.Errorf("storage: key does not belong to owner")
	}
	// Must have content after the owner prefix (at least "type/file")
	rest := key[len(prefix):]
	if rest == "" || !strings.Contains(rest, "/") {
		return fmt.Errorf("storage: key has invalid structure")
	}
	return nil
}

