func TestKeyFor(t *testing.T) {
	ownerID := uuid.MustParse("11111111-1111-1111-1111-111111111111")
	itemID := uuid.MustParse("22222222-2222-2222-2222-222222222222")

	tests := []struct {
		name     string
		itemType string
		filename string
		want     string
	}{
		{
			name:     "basic key",
			itemType: "bookmarks",
			filename: "content.html",
			want:     "11111111-1111-1111-1111-111111111111/bookmarks/22222222-2222-2222-2222-222222222222/content.html",
		},
		{
			name:     "nested filename",
			itemType: "files",
			filename: "document.pdf",
			want:     "11111111-1111-1111-1111-111111111111/files/22222222-2222-2222-2222-222222222222/document.pdf",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := KeyFor(ownerID, tt.itemType, itemID, tt.filename)
			if got != tt.want {
				t.Errorf("KeyFor() = %q, want %q", got, tt.want)
			}
		})
	}
}

func TestBookmarkKey(t *testing.T) {
	ownerID := uuid.MustParse("11111111-1111-1111-1111-111111111111")
	itemID := uuid.MustParse("22222222-2222-2222-2222-222222222222")

	got := BookmarkKey(ownerID, itemID)
	want := "11111111-1111-1111-1111-111111111111/bookmarks/22222222-2222-2222-2222-222222222222/content.html"
	if got != want {
		t.Errorf("BookmarkKey() = %q, want %q", got, want)
	}
}

func TestAudioKey(t *testing.T) {
	ownerID := uuid.MustParse("11111111-1111-1111-1111-111111111111")
	itemID := uuid.MustParse("22222222-2222-2222-2222-222222222222")

	tests := []struct {
		format string
