package item

import (
	"github.com/jackc/pgx/v5"
)

// scanItem scans a single row into an Item.
func scanItem(row pgx.Row) (*Item, error) {
	var it Item
	err := row.Scan(
		&it.ID, &it.OwnerID, &it.Type, &it.Status, &it.Sensitivity,
		&it.Title, &it.ContentText, &it.ContentURL,
		&it.Tags, &it.Metadata, &it.AutoMetadata,
		&it.Source, &it.SourceURL,
		&it.CreatedAt, &it.UpdatedAt, &it.CapturedAt,
	)
	if err != nil {
		return nil, err
	}
	return &it, nil
}

// scanItems scans multiple rows into a slice of Items.
func scanItems(rows pgx.Rows) ([]*Item, error) {
	var items []*Item
	for rows.Next() {
		var it Item
		err := rows.Scan(
			&it.ID, &it.OwnerID, &it.Type, &it.Status, &it.Sensitivity,
			&it.Title, &it.ContentText, &it.ContentURL,
			&it.Tags, &it.Metadata, &it.AutoMetadata,
			&it.Source, &it.SourceURL,
			&it.CreatedAt, &it.UpdatedAt, &it.CapturedAt,
		)
		if err != nil {
			return nil, err
		}
		items = append(items, &it)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	if items == nil {
		items = []*Item{}
	}
	return items, nil
}

