package item

import (
	"fmt"
	"strings"
)

// queryBuilder constructs a dynamic WHERE clause with parameterized conditions.
type queryBuilder struct {
	conditions []string
	args       []any
}

// add appends a condition with a single parameter. Use %d as the placeholder
// position in the condition template (e.g., "type = $%d").
func (qb *queryBuilder) add(conditionTemplate string, arg any) {
	qb.args = append(qb.args, arg)
	qb.conditions = append(qb.conditions, fmt.Sprintf(conditionTemplate, len(qb.args)))
}

// where returns the WHERE clause string (including "WHERE") or empty string if
// no conditions were added.
func (qb *queryBuilder) where() string {
	if len(qb.conditions) == 0 {
		return ""
	}
	return "WHERE " + strings.Join(qb.conditions, " AND ")
}

// nextParam returns the next parameter placeholder number without adding a condition.
func (qb *queryBuilder) nextParam() int {
	return len(qb.args) + 1
}

// sortFieldToColumn maps GraphQL sort field names to database column names.
// Returns the column name and true if valid, or empty string and false if not.
func sortFieldToColumn(field string) (string, bool) {
	switch strings.ToUpper(field) {
	case "CREATED_AT":
		return "created_at", true
	case "UPDATED_AT":
		return "updated_at", true
	case "CAPTURED_AT":
		return "captured_at", true
	case "TITLE":
		return "title", true
	default:
		return "", false
	}
}

// sortDirectionSQL returns "ASC" or "DESC". Defaults to "DESC" for invalid input.
func sortDirectionSQL(dir string) string {
	if strings.ToUpper(dir) == "ASC" {
		return "ASC"
	}
	return "DESC"
}

// applyFilter adds filter conditions to the query builder.
func applyFilter(qb *queryBuilder, f *Filter) {
	if f == nil {
		return
	}
	if len(f.Types) == 1 {
		qb.add("type = $%d", f.Types[0])
	} else if len(f.Types) > 1 {
		qb.add("type = ANY($%d)", f.Types)
	}
	if len(f.Status) == 1 {
		qb.add("status = $%d", f.Status[0])
	} else if len(f.Status) > 1 {
		qb.add("status = ANY($%d)", f.Status)
	}
	if len(f.Sensitivity) == 1 {
		qb.add("sensitivity = $%d", f.Sensitivity[0])
	} else if len(f.Sensitivity) > 1 {
		qb.add("sensitivity = ANY($%d)", f.Sensitivity)
	}
	if len(f.Tags) > 0 {
		qb.add("tags && $%d", f.Tags)
	}
	if f.Source != nil {
		qb.add("source = $%d", *f.Source)
	}
	if f.DateFrom != nil {
		qb.add("created_at >= $%d", *f.DateFrom)
	}
	if f.DateTo != nil {
		qb.add("created_at <= $%d", *f.DateTo)
	}
}

// clampLimit ensures limit is between 1 and maxLimit.
func clampLimit(limit, maxLimit int) int {
	if limit <= 0 {
		return 20
	}
	if limit > maxLimit {
		return maxLimit
	}
	return limit
}

// clampOffset ensures offset is non-negative.
func clampOffset(offset int) int {
	if offset < 0 {
		return 0
	}
	return offset
}

