		Tools:          []string{"search", "capture"},
		MaxSensitivity: "sensitive",
	}

	data, err := json.Marshal(perms)
	if err != nil {
		t.Fatalf("Marshal: %v", err)
	}

	var decoded Permissions
	if err := json.Unmarshal(data, &decoded); err != nil {
		t.Fatalf("Unmarshal: %v", err)
