func TestLog_MarshalRequest(t *testing.T) {
	// Log with nil pool will panic on Exec, but we can test that marshal errors
	// are handled gracefully by using an unmarshalable request value.
	logger := New(nil)

	// A valid request should marshal fine — we test that the marshal path works
	// by testing the JSON output of a sample entry.
	e := Entry{
		UserID:       uuid.New(),
		Action:       "test.action",
		ResourceType: "item",
		Request:      map[string]any{"query": "test search"},
	}

	data, err := json.Marshal(e.Request)
	if err != nil {
		t.Fatalf("expected Request to marshal: %v", err)
	}
	if len(data) == 0 {
		t.Fatal("expected non-empty JSON")
	}

	// Verify the logger exists and doesn't panic on construction
	_ = logger
}

func TestLog_MarshalResponseSummary(t *testing.T) {
	e := Entry{
		UserID:          uuid.New(),
		Action:          "mcp.capture",
		ResourceType:    "item",
		ResourceID:      ptrUUID(uuid.New()),
		ResponseSummary: map[string]any{"status": "ok", "count": 42},
	}

	data, err := json.Marshal(e.ResponseSummary)
	if err != nil {
		t.Fatalf("expected ResponseSummary to marshal: %v", err)
	}
	if len(data) == 0 {
		t.Fatal("expected non-empty JSON")
	}
}

func TestLog_NilResponseSummary(t *testing.T) {
	e := Entry{
		UserID:          uuid.New(),
		Action:          "mcp.search",
		ResourceType:    "item",
		Request:         map[string]any{"q": "hello"},
		ResponseSummary: nil,
	}

	// Verify nil ResponseSummary doesn't cause marshal issues
	if e.ResponseSummary != nil {
		t.Fatal("expected nil ResponseSummary")
	}

	// Marshal Request should still work
	data, err := json.Marshal(e.Request)
	if err != nil {
		t.Fatalf("marshal: %v", err)
	}
	if len(data) == 0 {
		t.Fatal("expected non-empty JSON for Request")
	}
}

func TestEntryFields_AllSet(t *testing.T) {
	userID := uuid.New()
	clientID := uuid.New()
	resourceID := uuid.New()
	approved := false

	e := Entry{
		UserID:          userID,
		ClientID:        &clientID,
		Action:          "mcp.capture_bookmark",
		ResourceType:    "item",
		ResourceID:      &resourceID,
		Request:         map[string]any{"url": "https://example.com"},
		ResponseSummary: map[string]any{"item_id": resourceID.String()},
		Approved:        &approved,
	}

	if e.UserID != userID {
		t.Errorf("UserID mismatch")
	}
	if *e.ClientID != clientID {
		t.Errorf("ClientID mismatch")
	}
	if e.Action != "mcp.capture_bookmark" {
		t.Errorf("Action = %q", e.Action)
	}
	if e.ResourceType != "item" {
		t.Errorf("ResourceType = %q", e.ResourceType)
	}
	if *e.ResourceID != resourceID {
		t.Errorf("ResourceID mismatch")
	}
	if *e.Approved != false {
		t.Errorf("Approved should be false")
	}
}

func ptrUUID(id uuid.UUID) *uuid.UUID {
	return &id
}

