	qr := &queryResolver{r}

	ctx := authedCtx(uuid.New())
	threshold := 0.5
	result, err := qr.Search(ctx, "test query", nil, nil, &threshold)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	// Should fall back to FTS
	if result.Total != 1 {
		t.Errorf("Total = %d, want 1 (FTS fallback)", result.Total)
	}
}

func TestQuerySearch_NoEmbedder(t *testing.T) {
	r := &Resolver{
		ItemService: &mockItems{searched: &item.SearchResult{
			Items: []*item.Item{},
			Total: 0,
		}},
		Embedder: nil,
	}
	qr := &queryResolver{r}

	ctx := authedCtx(uuid.New())
	threshold := 0.5
	result, err := qr.Search(ctx, "test", nil, nil, &threshold)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	// Should fall back to FTS (no embedder)
	if result == nil {
		t.Fatal("expected non-nil result")
	}
}

