package resolver

import (
	"context"
	"fmt"
	"testing"
	"time"

	"github.com/google/uuid"

	"github.com/ketang/flotsam/api/graph/model"
	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/user"
)

// --- mock user service ---

type mockUsers struct {
	created    *user.User
	byEmail    *user.User
	byID       *user.User
	createErr  error
	emailErr   error
	idErr      error
}

func (m *mockUsers) Create(_ context.Context, _, _, _ string) (*user.User, error) {
	return m.created, m.createErr
}
func (m *mockUsers) GetByEmail(_ context.Context, _ string) (*user.User, error) {
	return m.byEmail, m.emailErr
}
func (m *mockUsers) GetByID(_ context.Context, _ uuid.UUID) (*user.User, error) {
	return m.byID, m.idErr
}

// --- helpers ---

func testUser() *user.User {
	hash := "$2a$10$dummyhashvalue1234567890123456789012345678901"
	return &user.User{
		ID:           uuid.New(),
		Email:        "test@example.com",
		AuthProvider: "local",
		PasswordHash: &hash,
		CreatedAt:    time.Now(),
		UpdatedAt:    time.Now(),
	}
}

// --- Register tests ---

func TestRegister_Success(t *testing.T) {
	u := testUser()
	issuer := auth.NewIssuer("test-secret-key-for-testing", 24*time.Hour)

	r := &Resolver{
		UserService: &mockUsers{created: u},
		Issuer:      issuer,
	}
	mr := &mutationResolver{r}

	result, err := mr.Register(context.Background(), model.RegisterInput{
		Email:    "test@example.com",
		Password: "password123",
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result.Token == "" {
		t.Error("expected non-empty token")
	}
	if result.User == nil {
		t.Fatal("expected non-nil user")
	}
	if result.User.Email != "test@example.com" {
		t.Errorf("Email = %q", result.User.Email)
	}
}

func TestRegister_WithDisplayName(t *testing.T) {
	u := testUser()
	dn := "John Doe"
	u.DisplayName = &dn
	issuer := auth.NewIssuer("test-secret", 24*time.Hour)

	r := &Resolver{
		UserService: &mockUsers{created: u},
		Issuer:      issuer,
	}
	mr := &mutationResolver{r}

	displayName := "John Doe"
	result, err := mr.Register(context.Background(), model.RegisterInput{
		Email:       "john@example.com",
		Password:    "password123",
		DisplayName: &displayName,
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result.User.DisplayName == nil || *result.User.DisplayName != "John Doe" {
		t.Errorf("DisplayName = %v", result.User.DisplayName)
	}
}

func TestRegister_EmailTaken(t *testing.T) {
	r := &Resolver{
		UserService: &mockUsers{createErr: user.ErrEmailTaken},
	}
	mr := &mutationResolver{r}

	_, err := mr.Register(context.Background(), model.RegisterInput{
		Email:    "taken@example.com",
		Password: "password123",
	})
	if err == nil {
		t.Fatal("expected error for taken email")
	}
}

func TestRegister_ServiceError(t *testing.T) {
	r := &Resolver{
		UserService: &mockUsers{createErr: fmt.Errorf("db error")},
	}
	mr := &mutationResolver{r}

	_, err := mr.Register(context.Background(), model.RegisterInput{
		Email:    "test@example.com",
		Password: "password123",
	})
	if err == nil {
		t.Fatal("expected error")
	}
}

// --- Login tests ---

func TestLogin_Success(t *testing.T) {
	// Create a real hashed password for testing
	hash, err := auth.HashPassword("password123")
	if err != nil {
		t.Fatalf("HashPassword: %v", err)
	}
	u := testUser()
	u.PasswordHash = &hash

	issuer := auth.NewIssuer("test-secret", 24*time.Hour)
	r := &Resolver{
		UserService: &mockUsers{byEmail: u},
		Issuer:      issuer,
	}
	mr := &mutationResolver{r}

	result, err := mr.Login(context.Background(), model.LoginInput{
		Email:    "test@example.com",
		Password: "password123",
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result.Token == "" {
		t.Error("expected non-empty token")
	}
	if result.User.Email != "test@example.com" {
		t.Errorf("Email = %q", result.User.Email)
	}
}

func TestLogin_UserNotFound(t *testing.T) {
	r := &Resolver{
		UserService: &mockUsers{byEmail: nil},
	}
	mr := &mutationResolver{r}

	_, err := mr.Login(context.Background(), model.LoginInput{
		Email:    "nobody@example.com",
		Password: "password123",
	})
	if err == nil {
		t.Fatal("expected error for unknown user")
	}
}

func TestLogin_WrongPassword(t *testing.T) {
	hash, _ := auth.HashPassword("correctpassword")
	u := testUser()
	u.PasswordHash = &hash

	issuer := auth.NewIssuer("test-secret", 24*time.Hour)
	r := &Resolver{
		UserService: &mockUsers{byEmail: u},
		Issuer:      issuer,
	}
	mr := &mutationResolver{r}

	_, err := mr.Login(context.Background(), model.LoginInput{
		Email:    "test@example.com",
		Password: "wrongpassword",
	})
	if err == nil {
		t.Fatal("expected error for wrong password")
	}
}

func TestLogin_NilPasswordHash(t *testing.T) {
	u := testUser()
	u.PasswordHash = nil

	r := &Resolver{
		UserService: &mockUsers{byEmail: u},
	}
	mr := &mutationResolver{r}

	_, err := mr.Login(context.Background(), model.LoginInput{
		Email:    "test@example.com",
		Password: "password123",
	})
	if err == nil {
		t.Fatal("expected error for nil password hash (OAuth user)")
	}
}

func TestLogin_ServiceError(t *testing.T) {
	r := &Resolver{
		UserService: &mockUsers{emailErr: fmt.Errorf("db error")},
	}
	mr := &mutationResolver{r}

	_, err := mr.Login(context.Background(), model.LoginInput{
		Email:    "test@example.com",
		Password: "password123",
	})
	if err == nil {
		t.Fatal("expected error")
	}
}

// --- Me tests ---

func TestMe_Unauthenticated(t *testing.T) {
	r := &Resolver{
		UserService: &mockUsers{},
	}
	qr := &queryResolver{r}

	result, err := qr.Me(context.Background())
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result != nil {
		t.Error("expected nil for unauthenticated user")
	}
}

func TestMe_Success(t *testing.T) {
	u := testUser()
	r := &Resolver{
		UserService: &mockUsers{byID: u},
	}
	qr := &queryResolver{r}

	ctx := authedCtx(u.ID)
	result, err := qr.Me(ctx)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result == nil {
		t.Fatal("expected non-nil user")
	}
	if result.Email != "test@example.com" {
		t.Errorf("Email = %q", result.Email)
	}
}

func TestMe_UserNotFound(t *testing.T) {
	r := &Resolver{
		UserService: &mockUsers{byID: nil},
	}
	qr := &queryResolver{r}

	ctx := authedCtx(uuid.New())
	result, err := qr.Me(ctx)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result != nil {
		t.Error("expected nil for deleted user")
	}
}

func TestMe_ServiceError(t *testing.T) {
	r := &Resolver{
		UserService: &mockUsers{idErr: fmt.Errorf("db error")},
	}
	qr := &queryResolver{r}

	ctx := authedCtx(uuid.New())
	_, err := qr.Me(ctx)
	if err == nil {
		t.Fatal("expected error")
	}
}

