func TestCreate_EmailNormalization(t *testing.T) {
	svc := &Service{} // nil pool — we test validation paths only

	tests := []struct {
		name     string
		email    string
		password string
		wantErr  bool
	}{
		{"leading spaces", "  user@example.com", "password123", false},
		{"trailing spaces", "user@example.com  ", "password123", false},
		{"uppercase", "USER@EXAMPLE.COM", "password123", false},
		{"mixed case with spaces", "  User@Example.COM  ", "password123", false},
		{"whitespace only", "   ", "password123", true},
		{"at sign only", "@", "password123", false}, // passes email check, fails on DB
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := svc.Create(context.Background(), tt.email, tt.password, "")
			if tt.wantErr {
				if err == nil {
					t.Fatal("expected error")
				}
			} else {
				// These will fail on DB call (nil pool), which is expected
				// The important thing is they DON'T fail on validation
				if err != nil && strings.Contains(err.Error(), "invalid email") {
					t.Errorf("unexpected validation error for %q: %v", tt.email, err)
				}
			}
		})
	}
}

