	svc := &Service{}

	t.Run("exactly 8 chars passes validation", func(t *testing.T) {
		_, err := svc.Create(context.Background(), "test@example.com", "12345678", "")
		// Should pass validation (will fail on nil pool, but not on validation)
		if err != nil && strings.Contains(err.Error(), "at least 8") {
			t.Error("8-char password should pass validation")
		}
	})

	t.Run("7 chars fails validation", func(t *testing.T) {
		_, err := svc.Create(context.Background(), "test@example.com", "1234567", "")
		if err == nil {
			t.Fatal("expected error for 7-char password")
		}
		if !strings.Contains(err.Error(), "at least 8") {
			t.Errorf("expected 'at least 8' error, got: %v", err)
		}
	})
}

