package provider

import "context"

// RoutingEmbedder selects between a default (cloud) and local embedder
// based on content sensitivity.
type RoutingEmbedder struct {
	defaultProvider Embedder
	localProvider   Embedder
}

// NewRoutingEmbedder creates a routing embedder. If localProvider is nil,
// all requests are handled by the default provider.
func NewRoutingEmbedder(defaultProvider, localProvider Embedder) *RoutingEmbedder {
	return &RoutingEmbedder{
		defaultProvider: defaultProvider,
		localProvider:   localProvider,
	}
}

// Embed delegates to the default provider (backward-compatible).
func (r *RoutingEmbedder) Embed(ctx context.Context, text string) ([]float32, error) {
	return r.defaultProvider.Embed(ctx, text)
}

// EmbedWithSensitivity routes to the local provider for sensitive/private content.
func (r *RoutingEmbedder) EmbedWithSensitivity(ctx context.Context, text, sensitivity string) ([]float32, error) {
	return r.pick(sensitivity).Embed(ctx, text)
}

// Dimensions returns the default provider's dimensions.
func (r *RoutingEmbedder) Dimensions() int {
	return r.defaultProvider.Dimensions()
}

// DimensionsForSensitivity returns the dimensions of the provider that would
// be selected for the given sensitivity level.
func (r *RoutingEmbedder) DimensionsForSensitivity(sensitivity string) int {
	return r.pick(sensitivity).Dimensions()
}

func (r *RoutingEmbedder) pick(sensitivity string) Embedder {
	if r.localProvider != nil && isSensitive(sensitivity) {
		return r.localProvider
	}
	return r.defaultProvider
}

// RoutingClassifier selects between a default (cloud) and local classifier
// based on content sensitivity.
type RoutingClassifier struct {
	defaultProvider Classifier
	localProvider   Classifier
}

// NewRoutingClassifier creates a routing classifier. If localProvider is nil,
// all requests are handled by the default provider.
func NewRoutingClassifier(defaultProvider, localProvider Classifier) *RoutingClassifier {
	return &RoutingClassifier{
		defaultProvider: defaultProvider,
		localProvider:   localProvider,
	}
}

// Classify delegates to the default provider (backward-compatible).
func (r *RoutingClassifier) Classify(ctx context.Context, content string) (*Classification, error) {
	return r.defaultProvider.Classify(ctx, content)
}

// ClassifyWithSensitivity routes to the local provider for sensitive/private content.
func (r *RoutingClassifier) ClassifyWithSensitivity(ctx context.Context, content, sensitivity string) (*Classification, error) {
	if r.localProvider != nil && isSensitive(sensitivity) {
		return r.localProvider.Classify(ctx, content)
	}
	return r.defaultProvider.Classify(ctx, content)
}

// isSensitive returns true if the sensitivity level should use local providers.
func isSensitive(sensitivity string) bool {
	return sensitivity == "sensitive" || sensitivity == "private"
}

