package provider

import (
	"context"
	"fmt"
	"testing"
)

// mockEmbedder is a test double for the Embedder interface.
type mockEmbedder struct {
	name string
	dims int
}

func (m *mockEmbedder) Embed(_ context.Context, text string) ([]float32, error) {
	if text == "" {
		return nil, fmt.Errorf("empty input")
	}
	vec := make([]float32, m.dims)
	vec[0] = float32(m.dims) // encode dims as first value so tests can identify which provider was used
	return vec, nil
}

func (m *mockEmbedder) Dimensions() int { return m.dims }

// mockClassifier is a test double for the Classifier interface.
type mockClassifier struct {
	name string
}

func (m *mockClassifier) Classify(_ context.Context, content string) (*Classification, error) {
	if content == "" {
		return nil, fmt.Errorf("empty input")
	}
	return &Classification{
		Category: m.name,
		Summary:  "classified by " + m.name,
	}, nil
}

func TestRoutingEmbedder_NormalUsesDefault(t *testing.T) {
	defaultEmb := &mockEmbedder{name: "cloud", dims: 1536}
	localEmb := &mockEmbedder{name: "local", dims: 768}
	router := NewRoutingEmbedder(defaultEmb, localEmb)

	vec, err := router.EmbedWithSensitivity(context.Background(), "hello", "normal")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if vec[0] != 1536 {
		t.Errorf("expected default provider (1536), got %v", vec[0])
	}
}

func TestRoutingEmbedder_SensitiveUsesLocal(t *testing.T) {
	defaultEmb := &mockEmbedder{name: "cloud", dims: 1536}
	localEmb := &mockEmbedder{name: "local", dims: 768}
	router := NewRoutingEmbedder(defaultEmb, localEmb)

	for _, sensitivity := range []string{"sensitive", "private"} {
		vec, err := router.EmbedWithSensitivity(context.Background(), "hello", sensitivity)
		if err != nil {
			t.Fatalf("unexpected error for %s: %v", sensitivity, err)
		}
		if vec[0] != 768 {
			t.Errorf("expected local provider (768) for %s, got %v", sensitivity, vec[0])
		}
	}
}

func TestRoutingEmbedder_NilLocalFallsBack(t *testing.T) {
	defaultEmb := &mockEmbedder{name: "cloud", dims: 1536}
	router := NewRoutingEmbedder(defaultEmb, nil)

