import { Client, cacheExchange, fetchExchange } from 'urql'
import { authExchange } from '@urql/exchange-auth'
import { useAuthStore } from '@/stores/authStore'

export const urqlClient = new Client({
  url: '/graphql',
  exchanges: [
    cacheExchange,
    authExchange(async (utils) => ({
      addAuthToOperation(operation) {
        const token = useAuthStore.getState().getToken()
        if (!token) return operation
        return utils.appendHeaders(operation, {
          Authorization: `Bearer ${token}`,
        })
      },
      didAuthError(error) {
        return (
          error.graphQLErrors.some(
            (e) =>
              e.extensions?.code === 'FORBIDDEN' || e.extensions?.code === 'UNAUTHENTICATED',
          ) || error.response?.status === 401
        )
      },
      async refreshAuth() {
        useAuthStore.getState().logout()
      },
    })),
    fetchExchange,
  ],
})

import { useState } from 'react'
import { useNavigate, Link } from 'react-router-dom'
import { Container, Title, TextInput, PasswordInput, Button, Stack, Text, Alert } from '@mantine/core'
import { graphql } from 'gql.tada'
import { useMutation } from '@/lib/graphql'
import { useAuthStore } from '@/stores/authStore'

const LoginMutation = graphql(`
  mutation Login($input: LoginInput!) {
    login(input: $input) {
      token
      user {
        id
        email
        displayName
      }
    }
  }
`)

export function Login() {
  const navigate = useNavigate()
  const setAuth = useAuthStore((s) => s.setAuth)
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [, executeMutation] = useMutation(LoginMutation)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)

    const result = await executeMutation({ input: { email, password } })
    if (result.error) {
      setError(result.error.graphQLErrors[0]?.message ?? 'Login failed')
      return
    }

    const { token, user } = result.data.login
    setAuth(token, user)
    navigate('/')
  }

  return (
    <Container size="xs" py="xl">
      <Stack gap="lg">
        <Title order={2}>Login</Title>

        {error && (
          <Alert color="red" variant="light">
            {error}
          </Alert>
        )}

        <form onSubmit={handleSubmit}>
          <Stack gap="md">
            <TextInput
              label="Email"
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.currentTarget.value)}
            />
            <PasswordInput
              label="Password"
              required
              value={password}
              onChange={(e) => setPassword(e.currentTarget.value)}
            />
            <Button type="submit">Login</Button>
          </Stack>
        </form>

        <Text fz="sm" c="dimmed">
          Don&apos;t have an account?{' '}
          <Text component={Link} to="/register" c="brand.6" inherit>
            Register
          </Text>
        </Text>
      </Stack>
    </Container>
  )
}

