interface SearchItem {
  id: string
  type: string
  title: string | null
  contentText: string | null
  tags: string[]
  source: string
  sourceUrl: string | null
  capturedAt: string
}

interface SearchData {
  search: {
    items: SearchItem[]
    total: number
    hasMore: boolean
  }
}

const SearchQuery = graphql(`
  query Search($query: String!, $limit: Int, $filter: ItemFilter) {
    search(query: $query, limit: $limit, filter: $filter) {
      items {
        id
        type
        title
        contentText
        tags
        source
        sourceUrl
        capturedAt
      }
      total
      hasMore
    }
  }
`)

const TYPE_OPTIONS = [
  { value: 'BOOKMARK', label: 'Bookmarks' },
  { value: 'TEXT_NOTE', label: 'Notes' },
  { value: 'VOICE_NOTE', label: 'Voice' },
]

export function Search() {
  const [query, setQuery] = useState('')
  const [submitted, setSubmitted] = useState('')
  const [selectedTypes, setSelectedTypes] = useState<string[]>([])
  const [selectedTags, setSelectedTags] = useState<string[]>([])
  const [limit, setLimit] = useState(20)

  const filter = useMemo(() => {
    const f: Record<string, unknown> = {}
    if (selectedTypes.length > 0) f.types = selectedTypes
    if (selectedTags.length > 0) f.tags = selectedTags
    return Object.keys(f).length > 0 ? f : undefined
  }, [selectedTypes, selectedTags])

  const [result] = useQuery<SearchData>({
    query: SearchQuery,
    variables: { query: submitted, limit, filter },
    pause: !submitted,
  })

  const items = result.data?.search.items ?? []
  const hasMore = result.data?.search.hasMore ?? false

  // Collect unique tags from results for tag filtering
  const availableTags = useMemo(() => {
    const resultItems = result.data?.search.items
    if (!resultItems) return []
    const tagSet = new Set<string>()
    resultItems.forEach((item) => item.tags.forEach((tag) => tagSet.add(tag)))
    return Array.from(tagSet).sort()
  }, [result.data?.search.items])

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setLimit(20)
    setSubmitted(query.trim())
  }

  function handleLoadMore() {
    setLimit((prev) => prev + 20)
  }

  return (
    <Container size="md" py="xl">
      <Stack gap="lg">
        <Title order={2}>Search</Title>

        <form onSubmit={handleSubmit}>
          <TextInput
            placeholder="Search your knowledge base..."
            leftSection={<SearchIcon size={16} />}
            value={query}
            onChange={(e) => setQuery(e.currentTarget.value)}
            size="md"
          />
        </form>

        {/* Type filter */}
        <Chip.Group multiple value={selectedTypes} onChange={setSelectedTypes}>
          <Group gap="xs">
            {TYPE_OPTIONS.map((opt) => (
              <Chip key={opt.value} value={opt.value} size="xs" variant="outline">
                {opt.label}
              </Chip>
            ))}
          </Group>
        </Chip.Group>

        {/* Tag filter — shown when tags are available */}
        {availableTags.length > 0 && (
          <Chip.Group multiple value={selectedTags} onChange={setSelectedTags}>
            <Group gap="xs">
              {availableTags.map((tag) => (
                <Chip key={tag} value={tag} size="xs" variant="outline" color="accent">
                  {tag}
                </Chip>
              ))}
            </Group>
          </Chip.Group>
        )}

        {result.fetching && <Loader size="sm" />}

        {result.error && (
          <Text c="red" fz="sm">
            {result.error.message}
          </Text>
        )}

        {result.data && (
          <Stack gap="sm">
            <Text fz="sm" c="dimmed">
              {result.data.search.total} result{result.data.search.total !== 1 ? 's' : ''}
            </Text>

            {items.map((item) => (
              <ItemCard key={item.id} item={item} />
            ))}

            {hasMore && (
              <Button variant="subtle" onClick={handleLoadMore} fullWidth>
                Load more
              </Button>
            )}
          </Stack>
        )}

        {submitted && !result.fetching && result.data?.search.total === 0 && (
          <Text c="dimmed" ta="center" py="xl">
            No results found.
          </Text>
        )}
      </Stack>
    </Container>
  )
}

/**
 * Strict GraphQL utilities — re-exports urql hooks with types that reject raw strings.
 *
 * Import useQuery/useMutation from here instead of 'urql'. Raw string queries
 * bypass gql.tada's compile-time schema validation.
 *
 * Usage:
 *   import { graphql } from 'gql.tada'
 *   import { useQuery, useMutation } from '@/lib/graphql'
 *
 *   const MyQuery = graphql(`query MyQuery { ... }`)
 *   const [result] = useQuery({ query: MyQuery })
 */

import {
  useQuery as _useQuery,
  useMutation as _useMutation,
  type UseQueryResponse,
  type UseMutationResponse,
  type AnyVariables,
  type OperationContext,
  type RequestPolicy,
} from 'urql'

interface ParsedDocument {
  readonly kind: string
  readonly definitions: readonly unknown[]
}

interface StrictQueryArgs<Variables extends AnyVariables = AnyVariables> {
  query: ParsedDocument
  variables?: Variables
  requestPolicy?: RequestPolicy
  context?: Partial<OperationContext>
  pause?: boolean
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useQuery<Data = any, Variables extends AnyVariables = AnyVariables>(
  args: StrictQueryArgs<Variables>,
): UseQueryResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useQuery(args as any)
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useMutation<Data = any, Variables extends AnyVariables = AnyVariables>(
  query: ParsedDocument,
): UseMutationResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useMutation(query as any)
}

import { useState } from 'react'
import { useNavigate, Link } from 'react-router-dom'
import { Container, Title, TextInput, PasswordInput, Button, Stack, Text, Alert } from '@mantine/core'
import { graphql } from 'gql.tada'
import { useMutation } from '@/lib/graphql'
import { useAuthStore } from '@/stores/authStore'

const RegisterMutation = graphql(`
  mutation Register($input: RegisterInput!) {
    register(input: $input) {
      token
      user {
        id
        email
        displayName
      }
    }
  }
`)

export function Register() {
  const navigate = useNavigate()
  const setAuth = useAuthStore((s) => s.setAuth)
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [displayName, setDisplayName] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [, executeMutation] = useMutation(RegisterMutation)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)

    const result = await executeMutation({
      input: { email, password, displayName: displayName || undefined },
    })
    if (result.error) {
      setError(result.error.graphQLErrors[0]?.message ?? 'Registration failed')
      return
    }

    const { token, user } = result.data.register
    setAuth(token, user)
    navigate('/')
  }

  return (
    <Container size="xs" py="xl">
      <Stack gap="lg">
        <Title order={2}>Create an account</Title>

        {error && (
          <Alert color="red" variant="light">
            {error}
          </Alert>
        )}

        <form onSubmit={handleSubmit}>
          <Stack gap="md">
            <TextInput
              label="Email"
              type="email"
              required
              value={email}
              onChange={(e) => setEmail(e.currentTarget.value)}
            />
            <TextInput
              label="Display name"
              value={displayName}
              onChange={(e) => setDisplayName(e.currentTarget.value)}
            />
            <PasswordInput
              label="Password"
              required
              value={password}
              onChange={(e) => setPassword(e.currentTarget.value)}
            />
            <Button type="submit">Register</Button>
          </Stack>
        </form>

        <Text fz="sm" c="dimmed">
          Already have an account?{' '}
          <Text component={Link} to="/login" c="brand.6" inherit>
            Login
          </Text>
        </Text>
      </Stack>
    </Container>
  )
}

