          <Tabs.Panel value="bookmark" pt="md">
            <BookmarkTab />
          </Tabs.Panel>

          <Tabs.Panel value="note" pt="md">
            <NoteTab />
          </Tabs.Panel>

          <Tabs.Panel value="voice" pt="md">
            <VoiceTab />
          </Tabs.Panel>
        </Tabs>
