import { Client, cacheExchange, fetchExchange } from 'urql'
import { authExchange } from '@urql/exchange-auth'
import { useAuthStore } from '@/stores/authStore'

export const urqlClient = new Client({
  url: '/graphql',
  exchanges: [
    cacheExchange,
    authExchange(async (utils) => ({
      addAuthToOperation(operation) {
        const token = useAuthStore.getState().getToken()
        if (!token) return operation
        return utils.appendHeaders(operation, {
          Authorization: `Bearer ${token}`,
        })
      },
      didAuthError(error) {
        return (
          error.graphQLErrors.some(
            (e) =>
              e.extensions?.code === 'FORBIDDEN' || e.extensions?.code === 'UNAUTHENTICATED',
          ) || error.response?.status === 401
        )
      },
      async refreshAuth() {
        useAuthStore.getState().logout()
      },
    })),
    fetchExchange,
  ],
})

import { create } from 'zustand'
import { urqlClient } from '@/lib/urqlClient'
import { MeQuery } from '@/lib/queries'

const TOKEN_KEY = 'flotsam_token'

export interface User {
  id: string
  email: string
  displayName: string | null
}

interface AuthState {
  token: string | null
  user: User | null
  loading: boolean

  initialize: () => Promise<void>
  setAuth: (token: string, user: User) => void
  logout: () => void
  getToken: () => string | null
}

export const useAuthStore = create<AuthState>()((set, get) => ({
  token: null,
  user: null,
  loading: true,

  initialize: async () => {
    const token = localStorage.getItem(TOKEN_KEY)
    if (!token) {
      set({ loading: false })
      return
    }

    set({ token })

    try {
      const result = await urqlClient.query(MeQuery, {}).toPromise()
      if (result.data?.me) {
        set({
          user: {
            id: result.data.me.id,
            email: result.data.me.email,
            displayName: result.data.me.displayName ?? null,
          },
          loading: false,
        })
      } else {
        // Token is invalid or expired
        get().logout()
        set({ loading: false })
      }
    } catch {
      // Network error or other failure — clear invalid session
      get().logout()
      set({ loading: false })
    }
  },

  setAuth: (token: string, user: User) => {
    localStorage.setItem(TOKEN_KEY, token)
    set({ token, user, loading: false })
  },

  logout: () => {
    localStorage.removeItem(TOKEN_KEY)
    set({ token: null, user: null })
  },

  getToken: () => {
    return get().token
  },
}))

import { Navigate, Outlet } from 'react-router-dom'
import { Center, Loader } from '@mantine/core'
import { useAuthStore } from '@/stores/authStore'

export function ProtectedRoute() {
  const token = useAuthStore((s) => s.token)
  const loading = useAuthStore((s) => s.loading)

  if (loading) {
    return (
      <Center h="60vh">
        <Loader size="lg" />
      </Center>
    )
  }

  if (!token) {
    return <Navigate to="/login" replace />
  }

  return <Outlet />
}

import { render, type RenderOptions } from '@testing-library/react'
import { MantineProvider } from '@mantine/core'
import { theme } from '../theme'

/** Wraps component in MantineProvider for tests that use Mantine components. */
export function renderWithMantine(ui: React.ReactElement, options?: RenderOptions) {
  return render(ui, {
    wrapper: ({ children }) => <MantineProvider theme={theme}>{children}</MantineProvider>,
    ...options,
  })
}

import { useNavigate } from 'react-router-dom'
import { Container, Title, Text, SimpleGrid, Card, Group, Button, Stack } from '@mantine/core'
import { Search, BookmarkPlus, FileText, Mic } from 'lucide-react'
import { useAuthStore } from '@/stores/authStore'

const FEATURES = [
  {
    icon: BookmarkPlus,
    title: 'Bookmarks',
    description: 'Save URLs with automatic page content extraction and metadata.',
  },
  {
    icon: FileText,
    title: 'Notes',
    description: 'Capture quick text notes with tags and categories.',
  },
  {
    icon: Mic,
    title: 'Voice Notes',
    description: 'Record voice memos with automatic transcription.',
  },
  {
    icon: Search,
    title: 'Semantic Search',
    description: 'Find anything with full-text and AI-powered semantic search.',
  },
]

export function Home() {
  const navigate = useNavigate()
  const token = useAuthStore((s) => s.token)

  return (
    <Container size="md" py="xl">
      <Stack gap="xl">
        <div>
          <Title order={1} c="brand.8">
            Your second brain
          </Title>
          <Text c="dimmed" fz="lg" mt="xs">
            Capture thoughts, bookmarks, and voice notes. Find them instantly with semantic search.
          </Text>
        </div>

        <Group gap="sm">
          <Button
            leftSection={<Search size={16} />}
            onClick={() => navigate('/search')}
          >
            Search
          </Button>
          {token ? (
            <Button
              variant="light"
              leftSection={<BookmarkPlus size={16} />}
              onClick={() => navigate('/capture')}
            >
              Capture
            </Button>
          ) : (
            <Button variant="light" onClick={() => navigate('/login')}>
              Login to capture
            </Button>
          )}
        </Group>

        <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="lg">
          {FEATURES.map((feature) => (
            <Card key={feature.title} shadow="sm" padding="lg" radius="md" withBorder>
              <Group gap="sm" mb="xs">
                <feature.icon size={20} />
                <Text fw={600}>{feature.title}</Text>
              </Group>
              <Text fz="sm" c="dimmed">
                {feature.description}
              </Text>
            </Card>
          ))}
        </SimpleGrid>
      </Stack>
    </Container>
  )
}

