import { describe, it, expect, vi, beforeEach } from 'vitest'
import { screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MemoryRouter } from 'react-router-dom'
import { MantineProvider } from '@mantine/core'
import { render } from '@testing-library/react'
import { Provider as UrqlProvider } from 'urql'
import { theme } from '@/theme'
import { Browse } from './Browse'
import { createMockClient } from '@/test/mocks'

vi.mock('@/lib/graphql', async () => {
  const actual = await vi.importActual<typeof import('@/lib/graphql')>('@/lib/graphql')
  return {
    ...actual,
    useQuery: vi.fn(),
  }
})

import { useQuery } from '@/lib/graphql'
const mockUseQuery = vi.mocked(useQuery)

function renderBrowse() {
  const mockClient = createMockClient()
  return render(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    <UrqlProvider value={mockClient as any}>
      <MantineProvider theme={theme}>
        <MemoryRouter>
          <Browse />
        </MemoryRouter>
      </MantineProvider>
    </UrqlProvider>,
  )
}

const sampleItems = [
  {
    id: '1',
    type: 'BOOKMARK',
    title: 'Test Bookmark',
    contentText: 'Some content',
    tags: ['test'],
    source: 'web',
    sourceUrl: 'https://example.com',
    capturedAt: '2024-01-01T00:00:00Z',
  },
  {
    id: '2',
    type: 'TEXT_NOTE',
    title: 'Test Note',
    contentText: 'Note content',
    tags: [],
    source: 'web',
    sourceUrl: null,
    capturedAt: '2024-01-02T00:00:00Z',
  },
]

describe('Browse', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('renders the browse page title', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    mockUseQuery.mockReturnValue([{ fetching: false, stale: false } as any, vi.fn()])
    renderBrowse()
    expect(screen.getByText('Browse')).toBeInTheDocument()
  })

  it('renders type filter chips', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    mockUseQuery.mockReturnValue([{ fetching: false, stale: false } as any, vi.fn()])
    renderBrowse()
    expect(screen.getByText('Bookmarks')).toBeInTheDocument()
    expect(screen.getByText('Notes')).toBeInTheDocument()
    expect(screen.getByText('Voice')).toBeInTheDocument()
  })

  it('renders sort dropdown', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    mockUseQuery.mockReturnValue([{ fetching: false, stale: false } as any, vi.fn()])
    renderBrowse()
    expect(screen.getByText('Newest first')).toBeInTheDocument()
  })

  it('shows loading state', () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    mockUseQuery.mockReturnValue([{ fetching: true, stale: false } as any, vi.fn()])
    renderBrowse()
    expect(document.querySelector('.mantine-Loader-root')).toBeTruthy()
  })

  it('shows error state', () => {
    mockUseQuery.mockReturnValue([
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      { fetching: false, stale: false, error: { message: 'Network error' } } as any,
      vi.fn(),
    ])
    renderBrowse()
    expect(screen.getByText('Network error')).toBeInTheDocument()
  })

  it('shows items in grid view when data loaded', () => {
    mockUseQuery.mockReturnValue([
      {
        fetching: false,
        stale: false,
        data: { items: { items: sampleItems, total: 2, hasMore: false } },
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any,
      vi.fn(),
    ])
    renderBrowse()
    expect(screen.getByText('Test Bookmark')).toBeInTheDocument()
    expect(screen.getByText('Test Note')).toBeInTheDocument()
    expect(screen.getByText('Showing 1–2 of 2')).toBeInTheDocument()
  })

  it('shows empty state when no items', () => {
    mockUseQuery.mockReturnValue([
      {
        fetching: false,
        stale: false,
        data: { items: { items: [], total: 0, hasMore: false } },
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any,
      vi.fn(),
    ])
    renderBrowse()
    expect(screen.getByText('No items found.')).toBeInTheDocument()
  })

  it('shows pagination when total exceeds page size', () => {
    mockUseQuery.mockReturnValue([
      {
        fetching: false,
        stale: false,
        data: { items: { items: sampleItems, total: 25, hasMore: true } },
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any,
      vi.fn(),
    ])
    renderBrowse()
    expect(screen.getByText('Previous')).toBeInTheDocument()
    expect(screen.getByText('Next')).toBeInTheDocument()
    expect(screen.getByText('Page 1 of 2')).toBeInTheDocument()
  })

  it('switches to list view', async () => {
    mockUseQuery.mockReturnValue([
      {
        fetching: false,
        stale: false,
        data: { items: { items: sampleItems, total: 2, hasMore: false } },
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any,
      vi.fn(),
    ])
    renderBrowse()
    const segmented = document.querySelector('[class*="SegmentedControl"]')
    expect(segmented).toBeTruthy()
    // Items should be displayed
    expect(screen.getByText('Test Bookmark')).toBeInTheDocument()
  })

  it('clicks next page button', async () => {
    mockUseQuery.mockReturnValue([
      {
        fetching: false,
        stale: false,
        data: { items: { items: sampleItems, total: 25, hasMore: true } },
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any,
      vi.fn(),
    ])
    renderBrowse()
    const nextBtn = screen.getByText('Next')
    await userEvent.click(nextBtn)
    // After click, the component re-renders (useQuery is called again)
    expect(mockUseQuery).toHaveBeenCalled()
  })
})

